class Solution:
    def isIsomorphic(self, s: str, t: str) -> bool:
        if len(s) != len(t):
            return False
        ms, mt = {}, {}
        for a, b in zip(s, t):
            if ms.get(a, b) != b or mt.get(b, a) != a:
                return False
            ms[a] = b
            mt[b] = a
        return True

